-- 1. 清理所有測試相關的 assignments
DELETE FROM assignments WHERE workerId IN (
  SELECT id FROM workers WHERE name LIKE '%測試%' OR name LIKE '%TEST%' OR name LIKE '%test%' OR name LIKE '%核心流程%'
) OR demandId IN (
  SELECT id FROM demands WHERE note LIKE '%測試%' OR note LIKE '%TEST%' OR note LIKE '%test%' OR note LIKE '%核心流程%'
  OR clientId IN (SELECT id FROM clients WHERE name LIKE '%測試%' OR name LIKE '%TEST%' OR name LIKE '%test%' OR name LIKE '%核心流程%')
);

-- 2. 清理所有測試相關的 demands
DELETE FROM demands WHERE note LIKE '%測試%' OR note LIKE '%TEST%' OR note LIKE '%test%' OR note LIKE '%核心流程%'
  OR clientId IN (SELECT id FROM clients WHERE name LIKE '%測試%' OR name LIKE '%TEST%' OR name LIKE '%test%' OR name LIKE '%核心流程%');

-- 3. 清理所有測試相關的 availability
DELETE FROM availability WHERE workerId IN (
  SELECT id FROM workers WHERE name LIKE '%測試%' OR name LIKE '%TEST%' OR name LIKE '%test%' OR name LIKE '%核心流程%'
);

-- 4. 清理所有測試員工
DELETE FROM workers WHERE name LIKE '%測試%' OR name LIKE '%TEST%' OR name LIKE '%test%' OR name LIKE '%核心流程%';

-- 5. 清理所有測試客戶
